{
    public IReadOnlyCollection<TTestCase> OrderTestCases<TTestCase>(IReadOnlyCollection<TTestCase> testCases)
        where TTestCase : notnull, IXunitTestCase
    {
        return testCases.OrderBy(tc => tc.TestMethod?.MethodName).ToList();
    }
}

